#!/bin/bash
set -e
echo "Setting up Aurex MCP Agent..."
mkdir -p src bin

echo '' | base64 --decode > 'index.js'
echo '  done: index.js'
echo '' | base64 --decode > 'src/aurex-client.js'
echo '  done: src/aurex-client.js'
echo '' | base64 --decode > 'bin/cli.js'
echo '  done: bin/cli.js'
echo '' | base64 --decode > 'package.json'
echo '  done: package.json'
echo '' | base64 --decode > 'README.md'
echo '  done: README.md'
chmod +x bin/cli.js

echo ""
echo "All files created. Now:"
echo "  git add ."
echo '  git commit -m "feat: rewrite as MCP Server for Claude/Cursor"'
echo "  git push"
